class Solution:
    def subarrayGCD(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        from math import gcd

        count = 0

        for i in range(len(nums)):
            current_gcd = 0
            for j in range(i, len(nums)):
                current_gcd = gcd(current_gcd, nums[j])

                if current_gcd == k:
                    count += 1
                elif current_gcd < k:
                    # GCD can only decrease, stop if it's less than k
                    break

        return count
